#ifndef RMSNORM_H4096_KERNEL_H_
#define RMSNORM_H4096_KERNEL_H_

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>

#ifndef CHECK_CUDA
#define CHECK_CUDA(call)                                                      \
  do {                                                                        \
    cudaError_t err__ = (call);                                               \
    if (err__ != cudaSuccess) {                                               \
      printf("CUDA error %s at %s:%d\n", cudaGetErrorString(err__), __FILE__,  \
             __LINE__);                                                       \
    }                                                                         \
  } while (0)
#endif

// Kernel launcher (C++ callable)
void rmsnorm_h4096_launch(const __nv_bfloat16* hidden_states,
                          const __nv_bfloat16* weight,
                          __nv_bfloat16* output,
                          int64_t batch_size,
                          cudaStream_t stream);

#endif  // RMSNORM_H4096_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>

static __device__ __forceinline__ float bf16_to_f32(__nv_bfloat16 x) {
  return __bfloat162float(x);
}
static __device__ __forceinline__ __nv_bfloat16 f32_to_bf16_rn(float x) {
  return __float2bfloat16_rn(x);
}

// Warp + block reductions (sum)
static __device__ __forceinline__ float warp_reduce_sum(float v) {
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(0xffffffff, v, offset);
  }
  return v;
}

static __device__ __forceinline__ float block_reduce_sum(float v) {
  __shared__ float shared[32]; // up to 1024 threads => 32 warps
  int lane = threadIdx.x & 31;
  int wid  = threadIdx.x >> 5;

  v = warp_reduce_sum(v);
  if (lane == 0) shared[wid] = v;
  __syncthreads();

  // first warp finalizes
  v = (threadIdx.x < (blockDim.x >> 5)) ? shared[lane] : 0.0f;
  if (wid == 0) v = warp_reduce_sum(v);
  return v;
}

// One block handles one row (hidden_size fixed=4096).
// BLOCK=256 threads, each loads/stores 16 elements (4 float4 worth) => 4096 elems total.
// Two-pass: (1) sumsq in fp32, (2) normalize+scale and write bf16.
template<int BLOCK>
__global__ __launch_bounds__(BLOCK, 2)
void rmsnorm_h4096_kernel(const __nv_bfloat16* __restrict__ x,
                          const __nv_bfloat16* __restrict__ w,
                          __nv_bfloat16* __restrict__ y,
                          int64_t batch_size) {
  const int row = (int)blockIdx.x;
  if ((int64_t)row >= batch_size) return;

  constexpr int H = 4096;
  const int tid = threadIdx.x;
  const int row_offset = row * H;

  // Vectorized load of bf16x2 using int for alignment-safe access
  // We'll process 16 elements per thread: indices tid*16 + [0..15]
  const int base = tid * 16;

  float sumsq = 0.0f;

  #pragma unroll
  for (int i = 0; i < 16; i += 2) {
    const int idx = base + i; // 0..4094 step2
    // Load two bf16 packed
    const __nv_bfloat162* p = reinterpret_cast<const __nv_bfloat162*>(x + row_offset + idx);
    __nv_bfloat162 v2 = *p;
    float2 f2 = __bfloat1622float2(v2);
    sumsq = fmaf(f2.x, f2.x, sumsq);
    sumsq = fmaf(f2.y, f2.y, sumsq);
  }

  float total = block_reduce_sum(sumsq);
  __shared__ float inv_rms_shared;
  if (tid == 0) {
    // mean = total / 4096, inv_rms = rsqrt(mean + eps)
    const float mean = total * (1.0f / 4096.0f);
    const float eps = 1.0e-5f;
    inv_rms_shared = rsqrtf(mean + eps);
  }
  __syncthreads();
  const float inv_rms = inv_rms_shared;

  // Normalize and scale: y = (x*inv_rms) * w
  #pragma unroll
  for (int i = 0; i < 16; i += 2) {
    const int idx = base + i;
    const __nv_bfloat162 xv2 = *reinterpret_cast<const __nv_bfloat162*>(x + row_offset + idx);
    const __nv_bfloat162 wv2 = *reinterpret_cast<const __nv_bfloat162*>(w + idx);

    float2 xf = __bfloat1622float2(xv2);
    float2 wf = __bfloat1622float2(wv2);

    float2 yf;
    yf.x = (xf.x * inv_rms) * wf.x;
    yf.y = (xf.y * inv_rms) * wf.y;

    __nv_bfloat162 yb2 = __floats2bfloat162_rn(yf.x, yf.y);
    *reinterpret_cast<__nv_bfloat162*>(y + row_offset + idx) = yb2;
  }
}

void rmsnorm_h4096_launch(const __nv_bfloat16* hidden_states,
                          const __nv_bfloat16* weight,
                          __nv_bfloat16* output,
                          int64_t batch_size,
                          cudaStream_t stream) {
  if (batch_size <= 0) return;
  constexpr int BLOCK = 256;
  dim3 block(BLOCK);
  dim3 grid((uint32_t)batch_size);

  rmsnorm_h4096_kernel<BLOCK><<<grid, block, 0, stream>>>(
      hidden_states, weight, output, batch_size);

  // Note: errors checked on host side too; keep here for safety in non-torch use.
  (void)cudaGetLastError();
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#include <sstream>
#include <stdexcept>
#include <vector>

#include "kernel.h"

static void check_tensor(const torch::Tensor& t,
                         const char* name,
                         int64_t dim,
                         c10::ScalarType dtype,
                         bool cuda_required) {
  if (!t.defined()) {
    std::ostringstream oss; oss << name << " must be defined";
    throw std::invalid_argument(oss.str());
  }
  if (cuda_required && !t.device().is_cuda()) {
    std::ostringstream oss; oss << name << " must be a CUDA tensor";
    throw std::invalid_argument(oss.str());
  }
  if (t.scalar_type() != dtype) {
    std::ostringstream oss; oss << name << " must have dtype " << c10::toString(dtype)
                                << " but got " << c10::toString(t.scalar_type());
    throw std::invalid_argument(oss.str());
  }
  if (t.dim() != dim) {
    std::ostringstream oss; oss << name << " must have rank " << dim
                                << " but got " << t.dim();
    throw std::invalid_argument(oss.str());
  }
  if (!t.is_contiguous()) {
    std::ostringstream oss; oss << name << " must be contiguous";
    throw std::invalid_argument(oss.str());
  }
}

torch::Tensor run(torch::Tensor hidden_states, torch::Tensor weight) {
  // Validate
  check_tensor(hidden_states, "hidden_states", /*dim=*/2, /*dtype=*/c10::kBFloat16, /*cuda_required=*/true);
  check_tensor(weight, "weight", /*dim=*/1, /*dtype=*/c10::kBFloat16, /*cuda_required=*/true);

  const auto batch_size = hidden_states.size(0);
  const auto hidden_size = hidden_states.size(1);
  if (hidden_size != 4096) {
    std::ostringstream oss;
    oss << "hidden_states.size(1) must be 4096 but got " << hidden_size;
    throw std::invalid_argument(oss.str());
  }
  if (weight.size(0) != 4096) {
    std::ostringstream oss;
    oss << "weight.size(0) must be 4096 but got " << weight.size(0);
    throw std::invalid_argument(oss.str());
  }
  if (hidden_states.device() != weight.device()) {
    throw std::invalid_argument("hidden_states and weight must be on the same CUDA device");
  }

  auto output = torch::empty_like(hidden_states);

  const auto stream = at::cuda::getDefaultCUDAStream(hidden_states.device().index()).stream();

  const __nv_bfloat16* x_ptr = reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr<at::BFloat16>());
  const __nv_bfloat16* w_ptr = reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr<at::BFloat16>());
  __nv_bfloat16* y_ptr = reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>());

  rmsnorm_h4096_launch(x_ptr, w_ptr, y_ptr, batch_size, stream);

  // Error check + synchronize for correctness (Torch typically async; keep sync to satisfy spec)
  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA kernel launch failed: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }
  err = cudaDeviceSynchronize();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA synchronize failed: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "rmsnorm_h4096 (CUDA, BF16)");
}
